using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace Contoso.Orders;

[TestClass]
public sealed class OrderServiceTests
{
    private OrderService _sut = null!;

    [TestInitialize]
    public void Setup()
    {
        _sut = new OrderService();
    }

    // ── CreateOrder: Happy Path ──────────────────────────────────────

    [TestMethod]
    public void CreateOrder_SingleItem_ReturnsOrderWithCorrectProperties()
    {
        // Arrange
        var customerId = "CUST-001";
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 9.99m, Quantity = 2 }
        };

        // Act
        var order = _sut.CreateOrder(customerId, items);

        // Assert
        Assert.IsNotNull(order);
        Assert.IsNotNull(order.Id);
        Assert.AreEqual(customerId, order.CustomerId);
        Assert.AreEqual(1, order.Items.Count);
        Assert.AreEqual("Widget", order.Items[0].ProductName);
        Assert.AreEqual(9.99m, order.Items[0].Price);
        Assert.AreEqual(2, order.Items[0].Quantity);
        Assert.AreEqual(19.98m, order.Total);
        Assert.IsTrue(order.CreatedAt <= DateTime.UtcNow);
    }

    [TestMethod]
    public void CreateOrder_MultipleItems_ReturnsSumOfAllItemTotals()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "A", Price = 10.00m, Quantity = 1 },
            new() { ProductName = "B", Price = 5.50m, Quantity = 3 },
            new() { ProductName = "C", Price = 2.25m, Quantity = 4 }
        };

        // Act
        var order = _sut.CreateOrder("CUST-002", items);

        // Assert
        // 10*1 + 5.50*3 + 2.25*4 = 10 + 16.50 + 9 = 35.50
        Assert.AreEqual(35.50m, order.Total);
        Assert.AreEqual(3, order.Items.Count);
    }

    [TestMethod]
    [DataRow(1, 100.00, 100.00, DisplayName = "Quantity 1")]
    [DataRow(5, 20.00, 100.00, DisplayName = "Quantity 5")]
    [DataRow(10, 0.99, 9.90, DisplayName = "Fractional price")]
    [DataRow(1, 0.01, 0.01, DisplayName = "Minimum price")]
    public void CreateOrder_VariousPriceQuantityCombinations_CalculatesCorrectTotal(
        int quantity, double price, double expectedTotal)
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Product", Price = (decimal)price, Quantity = quantity }
        };

        // Act
        var order = _sut.CreateOrder("CUST-003", items);

        // Assert
        Assert.AreEqual((decimal)expectedTotal, order.Total);
    }

    [TestMethod]
    public void CreateOrder_ValidInput_AssignsUniqueIds()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 5.00m, Quantity = 1 }
        };

        // Act
        var order1 = _sut.CreateOrder("CUST-001", items);
        var order2 = _sut.CreateOrder("CUST-001", items);

        // Assert
        Assert.AreNotEqual(order1.Id, order2.Id);
    }

    [TestMethod]
    public void CreateOrder_ValidInput_SetsCreatedAtToRecentUtcTime()
    {
        // Arrange
        var before = DateTime.UtcNow;
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 1.00m, Quantity = 1 }
        };

        // Act
        var order = _sut.CreateOrder("CUST-001", items);
        var after = DateTime.UtcNow;

        // Assert
        Assert.IsTrue(order.CreatedAt >= before, "CreatedAt should be >= test start time");
        Assert.IsTrue(order.CreatedAt <= after, "CreatedAt should be <= test end time");
    }

    // ── CreateOrder: Error Cases ─────────────────────────────────────

    [TestMethod]
    public void CreateOrder_NullCustomerId_ThrowsArgumentNullException()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 1.00m, Quantity = 1 }
        };

        // Act & Assert
        Assert.ThrowsException<ArgumentNullException>(
            () => _sut.CreateOrder(null!, items));
    }

    [TestMethod]
    public void CreateOrder_NullItems_ThrowsArgumentNullException()
    {
        // Act & Assert
        Assert.ThrowsException<ArgumentNullException>(
            () => _sut.CreateOrder("CUST-001", null!));
    }

    [TestMethod]
    public void CreateOrder_EmptyItemsList_ThrowsInvalidOperationException()
    {
        // Arrange
        var items = new List<OrderItem>();

        // Act & Assert
        var ex = Assert.ThrowsException<InvalidOperationException>(
            () => _sut.CreateOrder("CUST-001", items));

        Assert.AreEqual("Cannot create an order with no items.", ex.Message);
    }

    // ── GetOrder ─────────────────────────────────────────────────────

    [TestMethod]
    public void GetOrder_ExistingOrderId_ReturnsMatchingOrder()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 15.00m, Quantity = 2 }
        };
        var created = _sut.CreateOrder("CUST-001", items);

        // Act
        var retrieved = _sut.GetOrder(created.Id);

        // Assert
        Assert.IsNotNull(retrieved);
        Assert.AreEqual(created.Id, retrieved.Id);
        Assert.AreEqual("CUST-001", retrieved.CustomerId);
        Assert.AreEqual(30.00m, retrieved.Total);
    }

    [TestMethod]
    public void GetOrder_NonExistentOrderId_ReturnsNull()
    {
        // Act
        var result = _sut.GetOrder("non-existent-id");

        // Assert
        Assert.IsNull(result);
    }

    [TestMethod]
    public void GetOrder_MultipleOrdersExist_ReturnsCorrectOne()
    {
        // Arrange
        var items1 = new List<OrderItem>
        {
            new() { ProductName = "Alpha", Price = 10.00m, Quantity = 1 }
        };
        var items2 = new List<OrderItem>
        {
            new() { ProductName = "Beta", Price = 20.00m, Quantity = 1 }
        };
        var order1 = _sut.CreateOrder("CUST-001", items1);
        var order2 = _sut.CreateOrder("CUST-002", items2);

        // Act
        var retrieved = _sut.GetOrder(order2.Id);

        // Assert
        Assert.IsNotNull(retrieved);
        Assert.AreEqual(order2.Id, retrieved.Id);
        Assert.AreEqual("CUST-002", retrieved.CustomerId);
        Assert.AreEqual(20.00m, retrieved.Total);
    }

    // ── GetOrdersByCustomer ──────────────────────────────────────────

    [TestMethod]
    public void GetOrdersByCustomer_CustomerWithOrders_ReturnsAllMatchingOrders()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 5.00m, Quantity = 1 }
        };
        _sut.CreateOrder("CUST-001", items);
        _sut.CreateOrder("CUST-001", items);
        _sut.CreateOrder("CUST-001", items);

        // Act
        var orders = _sut.GetOrdersByCustomer("CUST-001");

        // Assert
        Assert.AreEqual(3, orders.Count);
        Assert.IsTrue(orders.All(o => o.CustomerId == "CUST-001"));
    }

    [TestMethod]
    public void GetOrdersByCustomer_CustomerWithNoOrders_ReturnsEmptyList()
    {
        // Act
        var orders = _sut.GetOrdersByCustomer("CUST-NONE");

        // Assert
        Assert.IsNotNull(orders);
        Assert.AreEqual(0, orders.Count);
    }

    [TestMethod]
    public void GetOrdersByCustomer_MultipleCustomers_ReturnsOnlyMatchingCustomerOrders()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 5.00m, Quantity = 1 }
        };
        _sut.CreateOrder("CUST-001", items);
        _sut.CreateOrder("CUST-001", items);
        _sut.CreateOrder("CUST-002", items);
        _sut.CreateOrder("CUST-003", items);

        // Act
        var cust1Orders = _sut.GetOrdersByCustomer("CUST-001");
        var cust2Orders = _sut.GetOrdersByCustomer("CUST-002");
        var cust3Orders = _sut.GetOrdersByCustomer("CUST-003");

        // Assert
        Assert.AreEqual(2, cust1Orders.Count);
        Assert.AreEqual(1, cust2Orders.Count);
        Assert.AreEqual(1, cust3Orders.Count);
        Assert.IsTrue(cust1Orders.All(o => o.CustomerId == "CUST-001"));
        Assert.IsTrue(cust2Orders.All(o => o.CustomerId == "CUST-002"));
        Assert.IsTrue(cust3Orders.All(o => o.CustomerId == "CUST-003"));
    }

    // ── State / Integration ──────────────────────────────────────────

    [TestMethod]
    public void CreateOrder_ThenGetOrder_OrderIsRetrievable()
    {
